﻿"use client";

import { useEffect, useState } from "react";
import { Moon, Sun } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

export function ThemeToggle() {
  const [isDark, setIsDark] = useState(false);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setMounted(true);
    // Initialize state from DOM (which was set by our layout script)
    const isDarkMode = document.documentElement.classList.contains("dark");
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setIsDark(isDarkMode);
  }, []);

  const applyTheme = (nextDark: boolean) => {
    setIsDark(nextDark);
    if (nextDark) {
      document.documentElement.classList.add("dark");
      window.localStorage.setItem("theme", "dark");
    } else {
      document.documentElement.classList.remove("dark");
      window.localStorage.setItem("theme", "light");
    }
  };

  const toggleTheme = (event: React.MouseEvent) => {
    const nextDark = !isDark;

    // Fallback if browser doesn't support View Transitions API natively
    if (!document.startViewTransition) {
      applyTheme(nextDark);
      return;
    }

    const x = event.clientX;
    const y = event.clientY;

    const endRadius = Math.hypot(
      Math.max(x, window.innerWidth - x),
      Math.max(y, window.innerHeight - y)
    );

    const transition = document.startViewTransition(() => {
      applyTheme(nextDark);
    });

    transition.ready.then(() => {
      const clipPath = [
        `circle(0px at ${x}px ${y}px)`,
        `circle(${endRadius}px at ${x}px ${y}px)`
      ];

      document.documentElement.animate(
        {
          clipPath: clipPath,
        },
        {
          duration: 500,
          easing: "ease-in-out",
          pseudoElement: "::view-transition-new(root)",
        }
      );
    });
  };

  // Prevent hydration mismatch on the icon
  if (!mounted) return <div className="h-10 w-10" />;

  return (
    <button
      onClick={toggleTheme}
      className="relative flex h-10 w-10 items-center justify-center rounded-full bg-muted text-foreground transition-colors hover:bg-accent outline-none"
      aria-label="Toggle theme"
    >
      <AnimatePresence mode="wait" initial={false}>
        {isDark ? (
          <motion.div
            key="moon"
            initial={{ opacity: 0, rotate: -90, scale: 0.5 }}
            animate={{ opacity: 1, rotate: 0, scale: 1 }}
            exit={{ opacity: 0, rotate: 90, scale: 0.5 }}
            transition={{ duration: 0.3, ease: "backOut" }}
            className="absolute"
          >
            <Moon className="h-5 w-5" />
          </motion.div>
        ) : (
          <motion.div
            key="sun"
            initial={{ opacity: 0, rotate: 90, scale: 0.5 }}
            animate={{ opacity: 1, rotate: 0, scale: 1 }}
            exit={{ opacity: 0, rotate: -90, scale: 0.5 }}
            transition={{ duration: 0.3, ease: "backOut" }}
            className="absolute"
          >
            <Sun className="h-5 w-5" />
          </motion.div>
        )}
      </AnimatePresence>
    </button>
  );
}

import { Kafka } from "@upstash/kafka";

// Initializes the Serverless Kafka connection securely
// It relies on UPSTASH_KAFKA_REST_URL, UPSTASH_KAFKA_REST_USERNAME, and UPSTASH_KAFKA_REST_PASSWORD
// Ensure these are set in .env.local before triggering events in production.
const kafka = new Kafka({
  url: process.env.UPSTASH_KAFKA_REST_URL || "",
  username: process.env.UPSTASH_KAFKA_REST_USERNAME || "",
  password: process.env.UPSTASH_KAFKA_REST_PASSWORD || "",
});

export type EventType = "app_published" | "workflow_executed" | "user_joined";

export interface SystemEvent {
  id: string;
  type: EventType;
  timestamp: string;
  payload: Record<string, any>;
}

/**
 * EventPublisher: Securely forwards platform events into the Serverless Upstash Kafka queue.
 * By decoupling this execution, we guarantee that heavy downstream analytic hooks 
 * won't severely penalize the latency of the user's triggering HTTP request.
 */
export class EventPublisher {
  /**
   * Pushes an asynchronous fire-and-forget payload into the specified Kafka Topic.
   */
  static async publish(topic: string, type: EventType, payload: Record<string, any>) {
    try {
      // Validate credentials quickly to prevent hanging the Vercel branch unnecessarily
      if (!process.env.UPSTASH_KAFKA_REST_URL) {
        if (process.env.NODE_ENV === "development") {
          console.log(`[Kafka Mock] Published [${type}] into topic [${topic}]:`, payload);
          return { success: true, mocked: true };
        }
        throw new Error("Missing Upstash Kafka credentials globally. Event suppressed.");
      }

      const event: SystemEvent = {
        id: crypto.randomUUID(),
        type,
        timestamp: new Date().toISOString(),
        payload,
      };

      // Safely utilize the Upstash REST wrapper for connectionless messaging
      const producer = kafka.producer();
      await producer.produce(topic, {
        value: JSON.stringify(event),
      });

      return { success: true };
    } catch (error: unknown) {
      console.error(`[EventPublisher] CRITICAL FAILURE pushing into Kafka [${topic}]:`, error.message);
      // We purposefully DO NOT throw an error down further so as not to 
      // brick the User's UI flow (e.g., stopping a save just because analytics failed).
      return { success: false, error: error.message };
    }
  }
}

import { createServerClient } from '@supabase/ssr'
import { cookies } from 'next/headers'

export async function createInsforgeServer() {
  const cookieStore = await cookies()

  return createServerClient(
    process.env.NEXT_PUBLIC_INSFORGE_URL!,
    process.env.NEXT_PUBLIC_INSFORGE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) => {
              cookieStore.set(name, value, options)
            })
          } catch (error) {
            // The `setAll` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing user sessions.
          }
        },
      },
    }
  )
}

import { z } from "zod";

const BaseComponentSchema = z.object({
  type: z.string({
    message: "Component 'type' is required and must be a string",
  }),
}).passthrough();

const PageSchema: unknown = z.object({
  components: z.array(BaseComponentSchema as any).optional().default([] as any),
}).passthrough();

const AppConfigSchema: unknown = z.object({
  app: z.string().optional(),
  pages: z.array(PageSchema as any).optional().default([] as any),
  entities: z.record(z.string(), z.any()).optional()
}).passthrough();

export function validateConfig(configStr: string): { errors: string[], warnings: string[] } {
  try {
    const raw = JSON.parse(configStr);
    const result = AppConfigSchema.safeParse(raw);
    
    if (!result.success) {
      return {
        errors: (result.error.errors || result.error.issues || []).map((e: unknown) => `${(e.path && e.path.join('.')) || 'root'}: ${e.message}`),
        warnings: []
      };
    }
    
    // Custom logic warnings without breaking validation
    const warnings: string[] = [];
    if (!raw.app) warnings.push("App name ('app') is missing. A layout fallback will be used.");
    if (!raw.pages || raw.pages.length === 0) warnings.push("No pages defined. App will load completely blank.");
    
    return { errors: [], warnings };
  } catch (e: unknown) {
    return {
      errors: [`Invalid JSON Syntax: ${e.message}`],
      warnings: []
    }
  }
}

﻿import { Button } from "@/components/ui/button";
import { ArrowRight, Save, Play, Plus, Search } from "lucide-react";

export function ButtonAction({ label, variant = "default", icon, size = "default" }: { label?: string, variant?: "default" | "outline" | "secondary" | "ghost", icon?: string, size?: "default" | "sm" | "lg" | "icon" }) {
  const iconMap: Record<string, React.FC<unknown>> = {
    search: Search,
    play: Play,
    plus: Plus,
    save: Save,
    "arrow-right": ArrowRight
  };

  const IconComponent = icon ? iconMap[icon] : null;

  return (
    <Button 
      variant={variant || "default"} 
      size="sm" 
      className={`rounded-full px-5 py-4 font-semibold transition-all duration-300 active:scale-95 flex items-center ${
        (!variant || variant === "default") && "shadow-[0_10px_25px_-5px_rgba(156,135,218,0.3)] hover:shadow-[0_20px_35px_-5px_rgba(156,135,218,0.5)] hover:-translate-y-0.5 bg-brand hover:bg-brand-dark text-background text-brand-foreground"
      } ${
        variant === "outline" && "shadow-sm hover:shadow-md hover:-translate-y-0.5 bg-brand/5 border-2 border-brand/60 text-brand hover:bg-brand/10 hover:border-brand"
      } ${
        variant === "secondary" && "hover:-translate-y-0.5 shadow-sm hover:shadow-md bg-secondary text-secondary-foreground border border-border/50"
      }`}
    >
      {IconComponent && <IconComponent className="w-4 h-4 mr-2" />}
      {label || "Action"}
    </Button>
  );
}
